import { useEffect, useState } from "react";
import { issueService, userService, bookService } from "../services/api";
import MessageBanner from "../components/MessageBanner";

const IssueReturnPage = () => {
  const [users, setUsers] = useState([]);
  const [books, setBooks] = useState([]);
  const [userId, setUserId] = useState("");
  const [bookId, setBookId] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const loadData = async () => {
      try {
        setError("");
        const [usersRes, booksRes] = await Promise.all([userService.getAll(), bookService.getAll()]);
        setUsers(usersRes.data || []);
        setBooks(booksRes.data || []);
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load users and books");
      }
    };

    loadData();
  }, []);

  const onIssue = async () => {
    try {
      setMessage("");
      setError("");
      await issueService.issue({ userId, bookId });
      setMessage("Book issued successfully");
      const booksRes = await bookService.getAll();
      setBooks(booksRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to issue book");
    }
  };

  const onReturn = async () => {
    try {
      setMessage("");
      setError("");
      await issueService.returnBook({ userId, bookId });
      setMessage("Book returned successfully");
      const booksRes = await bookService.getAll();
      setBooks(booksRes.data || []);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to return book");
    }
  };

  return (
    <div>
      <h2 className="text-2xl font-semibold mb-6">Issue / Return</h2>
      <MessageBanner message={message} />
      <MessageBanner message={error} variant="error" />

      <div className="bg-white shadow rounded-lg p-4 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <select
            className="border rounded px-3 py-2"
            value={userId}
            onChange={(e) => setUserId(e.target.value)}
          >
            <option value="">Select User</option>
            {users.map((user) => (
              <option key={user._id} value={user._id}>
                {user.name} ({user.email})
              </option>
            ))}
          </select>

          <select
            className="border rounded px-3 py-2"
            value={bookId}
            onChange={(e) => setBookId(e.target.value)}
          >
            <option value="">Select Book</option>
            {books.map((book) => (
              <option key={book._id} value={book._id}>
                {book.title} (Available: {book.availableCopies})
              </option>
            ))}
          </select>
        </div>
        <div className="flex gap-3 mt-4">
          <button
            type="button"
            className="bg-indigo-700 text-white px-4 py-2 rounded hover:bg-indigo-600 disabled:bg-gray-400"
            onClick={onIssue}
            disabled={!userId || !bookId}
          >
            Issue Book
          </button>
          <button
            type="button"
            className="bg-emerald-700 text-white px-4 py-2 rounded hover:bg-emerald-600 disabled:bg-gray-400"
            onClick={onReturn}
            disabled={!userId || !bookId}
          >
            Return Book
          </button>
        </div>
      </div>

      <div className="bg-white shadow rounded-lg overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-100">
            <tr>
              <th className="p-3">Title</th>
              <th className="p-3">Author</th>
              <th className="p-3">Available</th>
              <th className="p-3">Total</th>
            </tr>
          </thead>
          <tbody>
            {books.map((book) => (
              <tr key={book._id} className="border-t">
                <td className="p-3">{book.title}</td>
                <td className="p-3">{book.author}</td>
                <td className="p-3">{book.availableCopies}</td>
                <td className="p-3">{book.quantity}</td>
              </tr>
            ))}
            {!books.length && (
              <tr>
                <td className="p-3 text-gray-500" colSpan="4">
                  No books available.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default IssueReturnPage;
